COLORS = ["#3266ad", "#1D9E75", "#BA7517", "#A32D2D"]

with st.sidebar:
    st.header("⚙️ הגדרות")
    selected = st.selectbox("בחר קובץ", list(DATA.keys()))

df = pd.DataFrame(DATA[selected])
df.columns = ["שם נקודה", "Y", "X"]
color = COLORS[list(DATA.keys()).index(selected)]

c1, c2, c3, c4 = st.columns(4)
c1.metric("נקודות", len(df))
c2.metric("טווח Y", f"{df['Y'].max() - df['Y'].min():.2f}")
c3.metric("טווח X", f"{df['X'].max() - df['X'].min():.2f}")
c4.metric("ערכים חסרים", int(df.isnull().sum().sum()))

st.divider()

col1, col2 = st.columns(2)

with col1:
    st.subheader("פיזור נקודות (X מול Y)")
    fig_scatter = px.scatter(df, x="X", y="Y", hover_name="שם נקודה", color_discrete_sequence=[color])
    fig_scatter.update_traces(marker=dict(size=5 if len(df) > 100 else 8))
    fig_scatter.update_layout(height=320, margin=dict(t=10, b=10))
    st.plotly_chart(fig_scatter, use_container_width=True)

with col2:
    st.subheader("השוואת גדלי קבצים")
    bar_df = pd.DataFrame({"קובץ": list(DATA.keys()), "נקודות": [len(v) for v in DATA.values()]})
    fig_bar = px.bar(bar_df, x="קובץ", y="נקודות", color="קובץ", color_discrete_sequence=COLORS)
    fig_bar.update_layout(height=320, margin=dict(t=10, b=10), showlegend=False, xaxis_tickangle=-20)
    st.plotly_chart(fig_bar, use_container_width=True)

st.divider()

st.subheader("10 נקודות ראשונות")
st.dataframe(df.head(10).reset_index(drop=True), use_container_width=True, hide_index=True)

st.divider()
csv = df.to_csv(index=False).encode("utf-8-sig")
st.download_button("⬇️ הורד CSV", data=csv, file_name=f"{selected}.csv", mime="text/csv")
